export declare const styles = "\n:host {\n  all: initial;\n  --pi-primary: #0b7f70;\n  --pi-primary-strong: #075f55;\n  --pi-text: #17202a;\n  --pi-muted: #5f6c7b;\n  --pi-border: #d9e2ec;\n  --pi-surface: #ffffff;\n  --pi-soft: #f5f8fb;\n  --pi-danger: #b42318;\n  --pi-success: #087443;\n  --pi-warning: #9a6700;\n  font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, \"Segoe UI\", sans-serif;\n}\n* {\n  box-sizing: border-box;\n}\nbutton,\ninput {\n  font: inherit;\n}\n.pi-overlay {\n  position: fixed;\n  inset: 0;\n  z-index: 2147483647;\n  display: grid;\n  place-items: center;\n  padding: 20px;\n  background: rgba(15, 23, 42, 0.54);\n}\n.pi-inline {\n  width: 100%;\n}\n.pi-modal {\n  width: min(100%, 460px);\n  max-height: min(760px, calc(100vh - 40px));\n  overflow: hidden;\n  border: 1px solid var(--pi-border);\n  border-radius: 8px;\n  background: var(--pi-surface);\n  color: var(--pi-text);\n  box-shadow: 0 24px 80px rgba(15, 23, 42, 0.28);\n}\n.pi-inline .pi-modal {\n  max-height: none;\n  box-shadow: none;\n}\n.pi-header,\n.pi-body,\n.pi-footer {\n  padding: 18px 20px;\n}\n.pi-header {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 16px;\n  border-bottom: 1px solid var(--pi-border);\n}\n.pi-brand {\n  display: flex;\n  align-items: center;\n  min-width: 0;\n  gap: 12px;\n}\n.pi-logo,\n.pi-logo-fallback {\n  width: 36px;\n  height: 36px;\n  flex: 0 0 auto;\n  border-radius: 8px;\n  object-fit: cover;\n}\n.pi-logo-fallback {\n  display: grid;\n  place-items: center;\n  background: var(--pi-primary);\n  color: #fff;\n  font-weight: 700;\n}\n.pi-title {\n  margin: 0;\n  overflow-wrap: anywhere;\n  font-size: 16px;\n  font-weight: 700;\n  line-height: 1.25;\n}\n.pi-subtitle {\n  margin: 3px 0 0;\n  color: var(--pi-muted);\n  font-size: 13px;\n}\n.pi-close {\n  width: 36px;\n  height: 36px;\n  border: 0;\n  border-radius: 8px;\n  background: transparent;\n  color: var(--pi-muted);\n  cursor: pointer;\n  font-size: 24px;\n  line-height: 1;\n}\n.pi-close:hover,\n.pi-close:focus-visible {\n  background: var(--pi-soft);\n  color: var(--pi-text);\n  outline: none;\n}\n.pi-body {\n  max-height: calc(100vh - 190px);\n  overflow-y: auto;\n}\n.pi-inline .pi-body {\n  max-height: none;\n}\n.pi-stack {\n  display: grid;\n  gap: 16px;\n}\n.pi-summary {\n  display: grid;\n  gap: 10px;\n  padding: 14px;\n  border: 1px solid var(--pi-border);\n  border-radius: 8px;\n  background: var(--pi-soft);\n}\n.pi-row {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 16px;\n  color: var(--pi-muted);\n  font-size: 14px;\n}\n.pi-row strong {\n  color: var(--pi-text);\n  font-weight: 700;\n  text-align: right;\n}\n.pi-row.pi-total {\n  margin-top: 2px;\n  padding-top: 10px;\n  border-top: 1px solid var(--pi-border);\n  color: var(--pi-text);\n}\n.pi-row.pi-total strong {\n  font-size: 18px;\n}\n.pi-tabs {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, minmax(110px, 1fr));\n  gap: 8px;\n}\n.pi-tab {\n  min-height: 40px;\n  border: 1px solid var(--pi-border);\n  border-radius: 8px;\n  background: #fff;\n  color: var(--pi-text);\n  cursor: pointer;\n  font-size: 13px;\n  font-weight: 650;\n}\n.pi-tab[aria-selected=\"true\"] {\n  border-color: var(--pi-primary);\n  background: color-mix(in srgb, var(--pi-primary) 12%, #fff);\n  color: var(--pi-primary-strong);\n}\n.pi-tab[disabled] {\n  cursor: not-allowed;\n  opacity: 0.55;\n}\n.pi-panel {\n  display: grid;\n  gap: 12px;\n}\n.pi-bank-box {\n  display: grid;\n  gap: 10px;\n  padding: 14px;\n  border: 1px solid var(--pi-border);\n  border-radius: 8px;\n}\n.pi-account {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 10px;\n}\n.pi-account-number {\n  font-size: 22px;\n  font-weight: 750;\n  letter-spacing: 0;\n  overflow-wrap: anywhere;\n}\n.pi-copy,\n.pi-primary,\n.pi-secondary {\n  min-height: 42px;\n  border-radius: 8px;\n  cursor: pointer;\n  font-weight: 700;\n}\n.pi-copy {\n  border: 1px solid var(--pi-border);\n  background: #fff;\n  color: var(--pi-text);\n  padding: 0 12px;\n}\n.pi-primary {\n  width: 100%;\n  border: 0;\n  background: var(--pi-primary);\n  color: #fff;\n}\n.pi-primary:hover,\n.pi-primary:focus-visible {\n  background: var(--pi-primary-strong);\n  outline: none;\n}\n.pi-secondary {\n  border: 1px solid var(--pi-border);\n  background: #fff;\n  color: var(--pi-text);\n  padding: 0 14px;\n}\n.pi-secondary:disabled {\n  cursor: wait;\n  opacity: 0.65;\n}\n.pi-status {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 12px;\n  padding: 10px 12px;\n  border-radius: 8px;\n  background: var(--pi-soft);\n  color: var(--pi-muted);\n  font-size: 13px;\n}\n.pi-status strong {\n  color: var(--pi-text);\n  font-weight: 700;\n  text-align: right;\n  text-transform: capitalize;\n}\n.pi-refresh {\n  width: 100%;\n}\n.pi-state {\n  display: grid;\n  justify-items: center;\n  gap: 10px;\n  padding: 28px 10px;\n  text-align: center;\n}\n.pi-spinner {\n  width: 34px;\n  height: 34px;\n  border: 3px solid var(--pi-border);\n  border-top-color: var(--pi-primary);\n  border-radius: 50%;\n  animation: pi-spin 0.8s linear infinite;\n}\n.pi-badge {\n  display: inline-grid;\n  place-items: center;\n  min-width: 36px;\n  height: 36px;\n  border-radius: 999px;\n  font-weight: 800;\n}\n.pi-badge-success {\n  background: #dcfce7;\n  color: var(--pi-success);\n}\n.pi-badge-error {\n  background: #fee4e2;\n  color: var(--pi-danger);\n}\n.pi-message {\n  margin: 0;\n  color: var(--pi-muted);\n  font-size: 14px;\n  line-height: 1.5;\n}\n.pi-error {\n  padding: 12px;\n  border: 1px solid #fecdca;\n  border-radius: 8px;\n  background: #fffbfa;\n  color: var(--pi-danger);\n  font-size: 14px;\n}\n.pi-unavailable {\n  padding: 12px;\n  border: 1px dashed var(--pi-border);\n  border-radius: 8px;\n  color: var(--pi-muted);\n  font-size: 14px;\n}\n.pi-footer {\n  display: flex;\n  justify-content: flex-end;\n  gap: 10px;\n  border-top: 1px solid var(--pi-border);\n}\n.pi-sr-only {\n  position: absolute;\n  width: 1px;\n  height: 1px;\n  padding: 0;\n  overflow: hidden;\n  clip: rect(0, 0, 0, 0);\n  white-space: nowrap;\n  border: 0;\n}\n@keyframes pi-spin {\n  to {\n    transform: rotate(360deg);\n  }\n}\n@media (max-width: 520px) {\n  .pi-overlay {\n    align-items: end;\n    padding: 12px;\n  }\n  .pi-modal {\n    width: 100%;\n    max-height: calc(100vh - 24px);\n  }\n  .pi-header,\n  .pi-body,\n  .pi-footer {\n    padding: 16px;\n  }\n  .pi-row,\n  .pi-account {\n    align-items: flex-start;\n    flex-direction: column;\n    gap: 6px;\n  }\n  .pi-row strong {\n    text-align: left;\n  }\n}\n";
